#include <bits/stdc++.h>
using namespace std;
const int MAXN = 60;
const int MAXV = 1200;
const int MAXSUM = MAXN * MAXV; // 72000
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N,K;cin>>N>>K;
        vector<int>a(N);
        for(int i=0;i<N;++i)cin>>a[i];
        int I = (K+1)/2; // floor((K+1)/2)
        int L = I-1;
        int R = K-I;
        double best = 1e100;
        for(int medIdx=0; medIdx<N; ++medIdx){
            int m = a[medIdx];
            // collect candidates
            vector<int> leftVals, rightVals;
            leftVals.reserve(N);
            rightVals.reserve(N);
            for(int i=0;i<N;++i){
                if(i==medIdx) continue;
                if(a[i]<=m) leftVals.push_back(a[i]);
                if(a[i]>=m) rightVals.push_back(a[i]);
            }
            if((int)leftVals.size()<L || (int)rightVals.size()<R) continue; // not enough elements
            // DP for left side
            vector< bitset<MAXSUM+1> > dpL(L+1);
            dpL[0][0]=1;
            for(int val:leftVals){
                for(int c=min(L,(int)leftVals.size()); c>=1; --c){
                    dpL[c] |= (dpL[c-1] << val);
                }
            }
            // DP for right side
            vector< bitset<MAXSUM+1> > dpR(R+1);
            dpR[0][0]=1;
            for(int val:rightVals){
                for(int c=min(R,(int)rightVals.size()); c>=1; --c){
                    dpR[c] |= (dpR[c-1] << val);
                }
            }
            // combine
            if(L==0 && R==0){
                double diff = fabs(m - (double)m); // zero
                best = min(best, diff);
                continue;
            }
            if(L==0){
                for(int sr=0; sr<=MAXSUM; ++sr) if(dpR[R][sr]){
                    long long total = (long long)sr + m;
                    double diff = fabs((double)total / K - m);
                    if(diff < best) best = diff;
                }
                continue;
            }
            if(R==0){
                for(int sl=0; sl<=MAXSUM; ++sl) if(dpL[L][sl]){
                    long long total = (long long)sl + m;
                    double diff = fabs((double)total / K - m);
                    if(diff < best) best = diff;
                }
                continue;
            }
            // both sides non‑empty
            for(int sl=0; sl<=MAXSUM; ++sl) if(dpL[L][sl]){
                // iterate possible sr
                // we can iterate all sr but break early if impossible; simple loop
                for(int sr=0; sr<=MAXSUM; ++sr) if(dpR[R][sr]){
                    long long total = (long long)sl + sr + m;
                    double diff = fabs((double)total / K - m);
                    if(diff < best) best = diff;
                }
            }
        }
        cout.setf(ios::fixed); cout<<setprecision(3)<<best<<"\n";
    }
    return 0;
}

